@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@if (_initError is not null)
{
    <div class="@($"flex items-center justify-center text-sm text-destructive border border-destructive/30 rounded-md bg-destructive/5 {Class}".Trim())" style="height: @Height;" @attributes="AdditionalAttributes">
        <span>@_initError</span>
    </div>
}
else
{
<div class="@($"flex flex-col gap-3 rounded-md border border-border/60 bg-card p-3 {Class}".Trim())" @attributes="AdditionalAttributes">
    @* Lumeo-styled toolbar above the FullCalendar canvas.
       FullCalendar's built-in header is hidden in JS (headerToolbar: false). *@
    <div class="flex flex-wrap items-center justify-between gap-2">
        <div class="flex items-center gap-1">
            <Button Variant="Button.ButtonVariant.Outline" Size="Button.ButtonSize.Sm" OnClick="PrevAsync" aria-label="@L["Scheduler.Previous"]">
                <SvgGlyph Svg="@(LumeoIcons.ChevronLeft)" class="h-4 w-4" />
            </Button>
            <Button Variant="Button.ButtonVariant.Outline" Size="Button.ButtonSize.Sm" OnClick="TodayAsync">@L["Scheduler.Today"]</Button>
            <Button Variant="Button.ButtonVariant.Outline" Size="Button.ButtonSize.Sm" OnClick="NextAsync" aria-label="@L["Scheduler.Next"]">
                <SvgGlyph Svg="@(LumeoIcons.ChevronRight)" class="h-4 w-4" />
            </Button>
        </div>
        <div class="flex-1 text-center text-sm font-medium text-foreground truncate px-2">
            @_title
        </div>
        <ToggleGroup Type="ToggleGroup.ToggleGroupType.Single"
                     Variant="ToggleGroup.ToggleGroupVariant.Outline"
                     Size="Lumeo.Size.Sm"
                     Value="@_currentViewValue"
                     ValueChanged="OnViewChangedAsync">
            <ToggleGroupItem Value="Month">@L["Scheduler.Month"]</ToggleGroupItem>
            <ToggleGroupItem Value="Week">@L["Scheduler.Week"]</ToggleGroupItem>
            <ToggleGroupItem Value="Day">@L["Scheduler.Day"]</ToggleGroupItem>
            <ToggleGroupItem Value="List">@L["Scheduler.List"]</ToggleGroupItem>
        </ToggleGroup>
    </div>

    @* Resource legend — rendered when Resources are provided.
       Uses simple color-coded dots; no FullCalendar Premium plugin required. *@
    @if (_resolvedResources is { Count: > 0 })
    {
        <div class="flex flex-wrap items-center gap-x-4 gap-y-1 px-1 pb-1" aria-label="@L["Scheduler.ResourceLegend"]">
            @foreach (var resource in _resolvedResources)
            {
                <div class="flex items-center gap-1.5 text-xs text-muted-foreground">
                    <span class="inline-block h-2.5 w-2.5 rounded-[calc(var(--radius)*2)] flex-shrink-0"
                          style="background: @(resource.Color ?? "var(--color-primary)")"></span>
                    <span>@resource.Title</span>
                </div>
            }
        </div>
    }

    <div @ref="_hostRef" style="height: @Height;"></div>
</div>
}

@code {
    // ── Core parameters ──────────────────────────────────────────────────
    [Parameter] public IEnumerable<SchedulerEvent>? Events { get; set; }
    [Parameter] public EventCallback<IEnumerable<SchedulerEvent>> EventsChanged { get; set; }
    [Parameter] public SchedulerView InitialView { get; set; } = SchedulerView.Month;
    [Parameter] public DateTime? InitialDate { get; set; }
    [Parameter] public bool Editable { get; set; } = true;
    [Parameter] public bool Selectable { get; set; } = true;
    [Parameter] public bool BusinessHours { get; set; }
    [Parameter] public string Height { get; set; } = "640px";
    [Parameter] public int FirstDayOfWeek { get; set; } = 1;
    [Parameter] public EventCallback<SchedulerEvent> OnEventClick { get; set; }
    [Parameter] public EventCallback<SchedulerDateRange> OnDateSelect { get; set; }
    [Parameter] public EventCallback<SchedulerEvent> OnEventChange { get; set; }

    // ── Time-grid display parameters ─────────────────────────────────────
    /// <summary>
    /// Show the current-time indicator line in time-grid views. Default: true.
    /// Maps to FullCalendar's <c>nowIndicator</c> option.
    /// </summary>
    [Parameter] public bool NowIndicator { get; set; } = true;

    /// <summary>
    /// Earliest visible time slot in time-grid views (e.g. 07:00).
    /// Maps to FullCalendar's <c>slotMinTime</c>. Default: 00:00 (FullCalendar shows the full day).
    /// </summary>
    [Parameter] public TimeOnly? SlotMinTime { get; set; }

    /// <summary>
    /// Latest visible time slot in time-grid views (e.g. 22:00).
    /// Maps to FullCalendar's <c>slotMaxTime</c>. Default: 24:00 (FullCalendar shows the full day).
    /// </summary>
    [Parameter] public TimeOnly? SlotMaxTime { get; set; }

    /// <summary>
    /// Duration of each time slot row in time-grid views.
    /// Maps to FullCalendar's <c>slotDuration</c> (formatted as HH:mm:ss). Default: 00:30:00.
    /// </summary>
    [Parameter] public TimeSpan? SlotDuration { get; set; }

    // ── Resource / color-coding parameters ──────────────────────────────
    /// <summary>
    /// Optional list of resources (people, rooms, equipment). When provided, events
    /// are color-coded by their <see cref="SchedulerEvent.ResourceId"/> and a legend
    /// is rendered above the calendar.
    /// <br />
    /// Note: this uses Lumeo's color-coding fallback, NOT FullCalendar Premium resource
    /// lanes (which require a paid FullCalendar Premium license not bundled here).
    /// </summary>
    [Parameter] public IReadOnlyList<SchedulerResource>? Resources { get; set; }

    // ── Event styling callbacks ──────────────────────────────────────────
    /// <summary>
    /// Optional callback that returns extra CSS class names for an event chip.
    /// The classes are appended to the FullCalendar event's <c>classNames</c>.
    /// Use for conditional styling without touching <see cref="SchedulerEvent.Color"/>.
    /// </summary>
    [Parameter] public Func<SchedulerEvent, string>? EventClassNames { get; set; }

    /// <summary>
    /// Optional callback that returns a CSS color string for an event.
    /// Applied as <c>backgroundColor</c> / <c>borderColor</c> in FullCalendar.
    /// Supersedes <see cref="SchedulerEvent.Color"/> when both are set; resource
    /// color applies as a fallback when neither is set.
    /// </summary>
    [Parameter] public Func<SchedulerEvent, string>? EventColor { get; set; }

    // ── Error handling ───────────────────────────────────────────────────
    /// <summary>
    /// Raised when JS initialization fails (e.g. CDN down, FullCalendar threw).
    /// The argument is the error message. When raised the component renders an
    /// error card instead of the calendar.
    /// </summary>
    [Parameter] public EventCallback<string> OnInitError { get; set; }

    // ── Standard pass-through ────────────────────────────────────────────
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private ElementReference _hostRef;
    private DotNetObjectReference<Scheduler>? _selfRef;
    private string? _instanceId;
    private bool _initialized;
    private string? _initError;
    private int _lastEventsHash;
    private SchedulerView _currentView;
    private string _currentViewValue => _currentView.ToString();
    private string _title = "";

    // Snapshot of the most recent events set — used by eventChange to build the
    // updated collection without reaching back into `Events` (which may have
    // been replaced by the parent since init).
    private List<SchedulerEvent> _events = new();

    // CONTROLLED discriminator: hash of the events collection most recently pushed via
    // EventsChanged (also re-synced whenever we adopt an authoritative Events collection).
    // A controlled parent re-render that echoes back this exact collection is safe to
    // ignore (keep in-flight state); any other collection is an authoritative assertion
    // (veto / normalization / reset) and must win.
    private int _lastPushedEventsHash;

    // Resolved resource lookup — built once and used for both legend rendering
    // and event color-coding in ToJsEvent.
    private List<SchedulerResource> _resolvedResources = new();
    private Dictionary<string, SchedulerResource> _resourceById = new(StringComparer.Ordinal);

    protected override void OnInitialized()
    {
        _currentView = InitialView;
        _events = Events?.ToList() ?? new List<SchedulerEvent>();
        _lastEventsHash = ComputeEventsHash(_events);
        _lastPushedEventsHash = _lastEventsHash;
        _title = ComputeTitle(InitialDate ?? DateTime.Today, _currentView);
        RebuildResourceLookup();
    }

    protected override async Task OnParametersSetAsync()
    {
        // Rebuild the resource lookup whenever the Resources param changes.
        RebuildResourceLookup();

        if (_initialized && Events is not null)
        {
            var incoming = Events.ToList();
            var hash = ComputeEventsHash(incoming);

            bool shouldAdopt;
            if (EventsChanged.HasDelegate)
            {
                // CONTROLLED: the parent owns the collection.
                // Echo of our own push (hash == _lastPushedEventsHash) → keep in-flight state.
                // Anything else (veto, normalization, reset) → adopt the parent's assertion.
                shouldAdopt = hash != _lastPushedEventsHash;
            }
            else
            {
                // UNCONTROLLED: component owns the live collection.
                // Adopt the parameter only when the parent genuinely changes it; a stale
                // re-render that re-supplies the same collection must not clobber local edits.
                shouldAdopt = hash != _lastEventsHash;
            }

            if (shouldAdopt)
            {
                _events = incoming;
                _lastPushedEventsHash = hash;
                await Interop.SchedulerSetEventsAsync(_instanceId!, incoming.Select(ToJsEvent).Cast<object>());
            }

            // Keep the uncontrolled discriminator pointing at the last Events hash observed.
            _lastEventsHash = hash;
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender || _initialized) return;

        _selfRef = DotNetObjectReference.Create(this);

        // Snapshot exactly what init is about to render. OnParametersSetAsync drops any
        // Events refresh that arrives while _initialized is still false (the init is an
        // async JS handshake), so the parent's latest events can land AFTER these options
        // were captured but BEFORE init completes. We re-read Events post-init and push
        // the delta so that mid-init refresh is never silently lost.
        var initEventsHash = _lastEventsHash;

        var options = new
        {
            view = InitialView.ToString(),
            initialDate = (InitialDate ?? DateTime.Today).ToString("yyyy-MM-dd"),
            events = _events.Select(ToJsEvent).ToArray(),
            editable = Editable,
            selectable = Selectable,
            businessHours = BusinessHours,
            height = Height,
            firstDay = FirstDayOfWeek,
            nowIndicator = NowIndicator,
            slotMinTime = SlotMinTime.HasValue ? SlotMinTime.Value.ToString("HH:mm:ss") : (string?)null,
            slotMaxTime = SlotMaxTime.HasValue ? SlotMaxTime.Value.ToString("HH:mm:ss") : (string?)null,
            slotDuration = SlotDuration.HasValue ? $"{(int)SlotDuration.Value.TotalHours:D2}:{SlotDuration.Value.Minutes:D2}:{SlotDuration.Value.Seconds:D2}" : (string?)null
        };

        try
        {
            _instanceId = await Interop.SchedulerInitAsync(_hostRef, _selfRef, options);
            _initialized = true;

            // Reconcile against the latest Events: if the parent swapped them while init
            // was in flight, init rendered the stale snapshot — push the current set now.
            if (Events is not null)
            {
                var current = Events.ToList();
                var currentHash = ComputeEventsHash(current);
                if (currentHash != initEventsHash)
                {
                    _events = current;
                    _lastEventsHash = currentHash;
                    _lastPushedEventsHash = currentHash;
                    await Interop.SchedulerSetEventsAsync(_instanceId, current.Select(ToJsEvent).Cast<object>());
                }
            }

            // Read the real title from FullCalendar now that the view is rendered.
            _title = await Interop.SchedulerGetTitleAsync(_instanceId);
            StateHasChanged();
        }
        catch (Microsoft.JSInterop.JSDisconnectedException)
        {
            // Circuit dropped mid-init (e.g. user navigated away during prerender
            // hand-off). Nothing to render; swallow as Gantt does.
        }
        catch (Microsoft.JSInterop.JSException ex)
        {
            _initError = ex.Message;
            Console.Error.WriteLine($"[Lumeo Scheduler] Init failed: {ex.Message}");
            if (OnInitError.HasDelegate)
                await OnInitError.InvokeAsync(ex.Message);
            StateHasChanged();
        }
    }

    private object ToJsEvent(SchedulerEvent ev)
    {
        // Determine the effective color: EventColor callback > event.Color > resource color.
        var effectiveColor = EventColor?.Invoke(ev)
            ?? ev.Color
            ?? (ev.ResourceId is not null && _resourceById.TryGetValue(ev.ResourceId, out var res) ? res.Color : null);

        // Effective class names: EventClassNames callback merged with event.ClassNames.
        var cbClasses = EventClassNames?.Invoke(ev);
        var effectiveClassNames = string.IsNullOrEmpty(cbClasses)
            ? ev.ClassNames
            : string.IsNullOrEmpty(ev.ClassNames) ? cbClasses : $"{ev.ClassNames} {cbClasses}";

        // For recurring events with DaysOfWeek we use FullCalendar's free simple
        // recurrence model: the start/end fields become time-of-day values only.
        if (ev.DaysOfWeek is { Count: > 0 })
        {
            // Cross-midnight / next-day recurring events: when the end time-of-day is at or
            // before the start time-of-day, emitting endTime literally (e.g. start 22:00,
            // end 02:00) hands FullCalendar an end EARLIER than the start, which it silently
            // mis-renders (zero/negative-length chip). Express the span as an explicit
            // duration instead — FullCalendar adds it to startTime per occurrence, correctly
            // carrying the event past midnight. The real elapsed span (End - Start) is the
            // source of truth, so even a >24h recurring window is represented faithfully.
            var span = ev.End - ev.Start;
            var crossesMidnight = ev.End.TimeOfDay <= ev.Start.TimeOfDay;
            return new
            {
                id = ev.Id,
                title = ev.Title,
                // Time-of-day string for recurring events (HH:mm:ss).
                startTime = ev.Start.ToString("HH:mm:ss"),
                // Same-day window: keep the literal endTime (unchanged normal path).
                // Cross-midnight window: omit endTime and supply a duration instead.
                endTime = crossesMidnight ? (string?)null : ev.End.ToString("HH:mm:ss"),
                duration = crossesMidnight && span > TimeSpan.Zero
                    ? $"{(int)span.TotalHours:D2}:{span.Minutes:D2}:{span.Seconds:D2}"
                    : (string?)null,
                daysOfWeek = ev.DaysOfWeek.Select(d => (int)d).ToArray(),
                startRecur = ev.Start.ToString("yyyy-MM-dd"),
                endRecur = ev.RecurrenceEnd.HasValue
                    ? ev.RecurrenceEnd.Value.ToString("yyyy-MM-dd")
                    : (string?)null,
                exdate = ev.ExceptionDates?.Select(d => d.ToString("yyyy-MM-dd")).ToArray(),
                allDay = ev.AllDay,
                color = effectiveColor,
                url = ev.Url,
                classNames = effectiveClassNames,
                extendedProps = ev.ExtendedProps
            };
        }

        // Standard (non-recurring) event.
        return new
        {
            id = ev.Id,
            title = ev.Title,
            start = ev.Start.ToString("o"),
            end = ev.End.ToString("o"),
            allDay = ev.AllDay,
            color = effectiveColor,
            url = ev.Url,
            classNames = effectiveClassNames,
            extendedProps = ev.ExtendedProps
        };
    }

    private void RebuildResourceLookup()
    {
        _resolvedResources = Resources?.ToList() ?? new List<SchedulerResource>();

        // Duplicate (or null) resource Ids must not throw. ToDictionary blows up on a
        // duplicate key, taking down the whole render; consumers may legitimately pass a
        // list with repeated/blank Ids (e.g. a merged or partially-populated source).
        // Build defensively instead — last entry wins, and null Ids are skipped (they can
        // never be matched by SchedulerEvent.ResourceId lookups anyway).
        var lookup = new Dictionary<string, SchedulerResource>(StringComparer.Ordinal);
        foreach (var r in _resolvedResources)
        {
            if (r.Id is null) continue;
            lookup[r.Id] = r;
        }
        _resourceById = lookup;
    }

    private static int ComputeEventsHash(IEnumerable<SchedulerEvent> events)
    {
        // Cheap identity hash good enough to detect "did the caller hand us a
        // new event list?" without triggering a JS round-trip on every render.
        var hash = new HashCode();
        foreach (var ev in events)
        {
            hash.Add(ev.Id);
            hash.Add(ev.Title);
            hash.Add(ev.Start);
            hash.Add(ev.End);
            hash.Add(ev.AllDay);
            hash.Add(ev.Color);
            hash.Add(ev.Url);
            hash.Add(ev.ResourceId);
            hash.Add(ev.ClassNames);
            hash.Add(ev.RecurrenceEnd);

            // Hash the recurrence rule by value — not just its length. Folding only
            // DaysOfWeek.Count missed edits that swap days without changing the count
            // (e.g. {Mon} → {Tue}), so the calendar never re-rendered.
            if (ev.DaysOfWeek is { Count: > 0 })
            {
                foreach (var d in ev.DaysOfWeek)
                    hash.Add((int)d);
            }

            // ExceptionDates carry real recurrence edits (skip/un-skip a day);
            // omitting them suppressed the JS round-trip entirely.
            if (ev.ExceptionDates is { Count: > 0 })
            {
                foreach (var ex in ev.ExceptionDates)
                    hash.Add(ex);
            }

            // ExtendedProps is arbitrary app metadata round-tripped to JS; fold a
            // stable per-entry signature so changing a value is detected.
            if (ev.ExtendedProps is { Count: > 0 })
            {
                foreach (var kvp in ev.ExtendedProps)
                {
                    hash.Add(kvp.Key);
                    hash.Add(kvp.Value);
                }
            }
        }
        return hash.ToHashCode();
    }

    private string ComputeTitle(DateTime date, SchedulerView view) => view switch
    {
        SchedulerView.Month => date.ToString("MMMM yyyy"),
        SchedulerView.Week => string.Format(L["Scheduler.WeekOf"], StartOfWeek(date).ToString("MMM d, yyyy")),
        SchedulerView.Day => date.ToString("dddd, MMM d, yyyy"),
        SchedulerView.List => date.ToString("MMMM yyyy"),
        _ => date.ToString("MMMM yyyy")
    };

    private DateTime StartOfWeek(DateTime date)
    {
        // FirstDayOfWeek is 0-6 (Sun-Sat).
        var first = (DayOfWeek)FirstDayOfWeek;
        var diff = (7 + (date.DayOfWeek - first)) % 7;
        return date.AddDays(-diff).Date;
    }

    private async Task PrevAsync()
    {
        if (_instanceId is null) return;
        await Interop.SchedulerPrevAsync(_instanceId);
        await RefreshTitleAsync();
    }

    private async Task NextAsync()
    {
        if (_instanceId is null) return;
        await Interop.SchedulerNextAsync(_instanceId);
        await RefreshTitleAsync();
    }

    private async Task TodayAsync()
    {
        if (_instanceId is null) return;
        await Interop.SchedulerTodayAsync(_instanceId);
        await RefreshTitleAsync();
    }

    private async Task OnViewChangedAsync(string? v)
    {
        if (_instanceId is null || string.IsNullOrEmpty(v)) return;
        if (!Enum.TryParse<SchedulerView>(v, out var parsed)) return;
        _currentView = parsed;
        await Interop.SchedulerChangeViewAsync(_instanceId, v);
        await RefreshTitleAsync();
    }

    private async Task RefreshTitleAsync()
    {
        if (_instanceId is null) return;
        _title = await Interop.SchedulerGetTitleAsync(_instanceId);
        StateHasChanged();
    }

    [JSInvokable]
    public async Task JsOnEventClick(SchedulerEvent ev)
    {
        if (OnEventClick.HasDelegate) await OnEventClick.InvokeAsync(ev);
    }

    [JSInvokable]
    public async Task JsOnDateSelect(SchedulerDateRange range)
    {
        if (OnDateSelect.HasDelegate) await OnDateSelect.InvokeAsync(range);
    }

    [JSInvokable]
    public async Task JsOnEventChange(SchedulerEvent ev)
    {
        // A drag/resize only changes the time window (Start/End/AllDay). The JS
        // payload (eventToJson) carries only id/title/start/end/allDay/color/url/
        // extendedProps, so wholesale-replacing the stored event flattened every
        // field it omits — DaysOfWeek/RecurrenceEnd/ExceptionDates/ResourceId/
        // ClassNames — turning a recurring event into a one-off. Merge the new
        // window onto the existing record so the rest of the rule survives.
        //
        // Reconcile by Id, but only when the Id resolves UNAMBIGUOUSLY. A blank Id can't
        // identify a unique record (a plain FindIndex would match the first blank-Id event,
        // or none), and a duplicate Id is genuinely ambiguous — silently mutating the first
        // match would corrupt the wrong record. In both cases skip the in-place merge and
        // surface only the JS payload, leaving the stored collection untouched.
        var matches = 0;
        var idx = -1;
        if (!string.IsNullOrEmpty(ev.Id))
        {
            for (var i = 0; i < _events.Count; i++)
            {
                if (_events[i].Id == ev.Id)
                {
                    matches++;
                    if (idx < 0) idx = i;
                }
            }
        }

        if (idx >= 0 && matches == 1)
        {
            var existing = _events[idx];
            ev = existing with { Start = ev.Start, End = ev.End, AllDay = ev.AllDay };
            _events[idx] = ev;
        }

        // Record _lastPushedEventsHash BEFORE invoking EventsChanged: a controlled parent
        // re-renders synchronously inside InvokeAsync, so OnParametersSetAsync must already
        // see this hash as "the value we just pushed" to distinguish an accepted echo (keep
        // in-flight state) from a veto (parent kept its old collection → roll back).
        _lastPushedEventsHash = ComputeEventsHash(_events);

        if (OnEventChange.HasDelegate) await OnEventChange.InvokeAsync(ev);
        if (EventsChanged.HasDelegate) await EventsChanged.InvokeAsync(_events.ToList());
    }

    public async ValueTask DisposeAsync()
    {
        if (_instanceId is not null)
        {
            try { await Interop.SchedulerDestroyAsync(_instanceId); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
        _selfRef?.Dispose();
    }
}

namespace Lumeo;

/// <summary>
/// A calendar/scheduler event. Used as the data contract between Blazor and the
/// FullCalendar JS wrapper.
/// </summary>
/// <param name="Id">Stable identifier used to reconcile edits back into the caller's collection.</param>
/// <param name="Title">The label rendered on the event chip.</param>
/// <param name="Start">Start timestamp (inclusive).</param>
/// <param name="End">End timestamp (exclusive, per FullCalendar convention).</param>
/// <param name="AllDay">When true the event is rendered in the all-day lane.</param>
/// <param name="Color">CSS color or variable reference, e.g. "var(--color-primary)".</param>
/// <param name="Url">Optional link opened on click instead of firing OnEventClick.</param>
/// <param name="ExtendedProps">Arbitrary app-level metadata round-tripped through the JS layer.</param>
/// <param name="DaysOfWeek">
/// For recurring events: the days of the week on which the event repeats.
/// Uses FullCalendar's free simple recurrence model (no premium rrule plugin required).
/// e.g. [DayOfWeek.Monday, DayOfWeek.Wednesday, DayOfWeek.Friday].
/// When set, <see cref="Start"/> and <see cref="End"/> provide the start/end times
/// (time-of-day part only) and <see cref="RecurrenceEnd"/> bounds the recurrence.
/// </param>
/// <param name="RecurrenceEnd">
/// Optional end date for a recurring event. The event will not appear after this date.
/// Only meaningful when <see cref="DaysOfWeek"/> is set.
/// </param>
/// <param name="ExceptionDates">
/// Dates on which a recurring event should be skipped (one-off exclusions).
/// Only meaningful when <see cref="DaysOfWeek"/> is set.
/// </param>
/// <param name="ResourceId">
/// Optional resource identifier. When a <c>Resources</c> list is provided on the
/// <see cref="Scheduler"/> component, events are color-coded by their resource and
/// a resource legend is rendered above the calendar.
/// </param>
/// <param name="ClassNames">
/// Extra CSS class names to apply to the event chip, as produced by the
/// <c>EventClassNames</c> callback on the Scheduler component (or set directly here).
/// </param>
public record SchedulerEvent(
    string Id,
    string Title,
    DateTime Start,
    DateTime End,
    bool AllDay = false,
    string? Color = null,
    string? Url = null,
    Dictionary<string, object>? ExtendedProps = null,
    IReadOnlyList<DayOfWeek>? DaysOfWeek = null,
    DateTime? RecurrenceEnd = null,
    IReadOnlyList<DateTime>? ExceptionDates = null,
    string? ResourceId = null,
    string? ClassNames = null
);

/// <summary>
/// A named resource (person, room, equipment) used by the Scheduler for
/// color-coding events. Does not require the FullCalendar Premium resource plugin.
/// </summary>
/// <param name="Id">Identifier matched against <see cref="SchedulerEvent.ResourceId"/>.</param>
/// <param name="Title">Display name shown in the resource legend.</param>
/// <param name="Color">
/// CSS color applied to events belonging to this resource when the event itself
/// does not supply its own <see cref="SchedulerEvent.Color"/>.
/// </param>
public record SchedulerResource(string Id, string Title, string? Color = null);

/// <summary>
/// A date range produced when the user drag-selects in the calendar.
/// </summary>
public record SchedulerDateRange(DateTime Start, DateTime End, bool AllDay);

/// <summary>
/// Built-in views exposed by the Lumeo scheduler. Maps onto FullCalendar's
/// dayGridMonth / timeGridWeek / timeGridDay / listWeek view names.
/// </summary>
public enum SchedulerView
{
    Month,
    Week,
    Day,
    List
}
